sql:
SELECT e.employee_id
FROM employees e
JOIN departments d ON e.employee_id = d.head_id;

external_knowledge:
- "riding the salary wave" is a metaphor for consistently earning a high salary; 
- "salary spoils" is a metaphor for the average salary; 
- "veterans" refers to employees who have been in the department for at least 5 years.

sql:
SELECT 'HR Administrator' as role_name, SUM(e.gross_salary) as total_gross_salary
FROM employees e
WHERE e.year = 2015;

SELECT department_id, MAX(gross_salary) AS highest_gross_salary
FROM employees
GROUP BY department_id;
